INSERT INTO public.photos VALUES (24703, 'Vista aâ”śÂ®rea Torre Ramona 1991', 'Foto: Archivo Taumar (Irene Taulâ”śÂ®s y Rafael Margalâ”śÂ®). Vista aâ”śÂ®rea parcial del barrio de Las Fuentes, con el parque Torre Ramona al fondo. Fuente: www.facebook.com/photo.php?fbid=1687671018123264&set=...', 1991, 1991, 1991, 'Anos 90', 'LAS FUENTES', 41.63996300, -0.86191300, '0101000020E610000075E95F92CA94EBBF35D3BD4EEAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22418452421.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22418452421.webp', 'https://www.flickr.com/photos/zaragozaantigua/22418452421/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24707, 'Las Fuentes 1980', 'Fronteriza imagen capturada en la zona de huerta de Las Fuentes ante las traseras de la barriada "Vizconde de Escoriaza" construida en 1953 para trabajadores de la empresa Los tranvâ”śÂˇas de Zaragoza S.A., con ingreso principal por la calle de Fray Luis Urbano. En primer tâ”śÂ®rmino, riego al aire derivado de la acequia de San Josâ”śÂ® cortado junto a las viviendas por un antiguo camino particular que pocos aâ”śâ–’os antes habâ”śÂˇa recibido el nombre de calle de San Adriâ”śĂ­n de Sasabe con un inequâ”śÂˇvoco carâ”śĂ­cter ultraperifâ”śÂ®rico. Hacia la izquierda se abren consecutivamente las calles de Rudesindo Nasarre, de La Amistad (redenominaciâ”śâ”‚n en 1979 de la calle de la Divisiâ”śâ”‚n Azul), y de Rodrigo Rebolledo, hasta donde se elevan los grandes bloques construidos durante la segunda mitad de los aâ”śâ–’os setenta, y que desde entonces cierran visualmente esta zona de la ciudad, eclipsando al Grupo de Viviendas Josâ”śÂ® Antonio Girâ”śâ”‚n y al gran colegio de Santo Domingo de Silos. Seis aâ”śâ–’os despuâ”śÂ®s de comenzar su andadura el Gran Archivo Zaragoza Antigua (GAZA), este 5 de agosto de 2020 continuamos en la tarea de compilar, ordenar, datar y comentar miles de referencias visuales de la ciudad de Zaragoza. Cumpleimâ”śĂ­genes feliz a todas las personas que comparten con nosotros esta aventura y que con su apoyo nos alientan a continuar.', 1980, 1980, 1980, 'Anos 80', 'LAS FUENTES', 41.64867300, -0.85749100, '0101000020E6100000A4A833F79070EBBF2C6684B707D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50191519842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50191519842.webp', 'https://www.flickr.com/photos/zaragozaantigua/50191519842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24708, 'Calle del Doctor Iranzo 1990', 'Imagen capturada en el solar localizado en el penâ”śâ•‘ltimo tramo de la calle del Doctor Iranzo, a la izquierda, y delimitado como nâ”¬â•‘ 90 de este vial entre las calles Tiermas y Escultor Benlliure, en el barrio de Las Fuentes. Al fondo, el inmueble del nâ”¬â•‘ 92 de esta misma calle, esquinero con las calles de Tiermas y de Josâ”śÂ® Martâ”śÂˇnez Ruiz "Azorâ”śÂˇn". A mediados de la dâ”śÂ®cada, sobre este solar que aquâ”śÂˇ aparece deficientemente vallado y en estado de degradaciâ”śâ”‚n, la empresa inmobiliaria propietaria construyâ”śâ”‚ finalmente un moderno bloque de viviendas.', 1990, 1990, 1990, 'Anos 90', 'LAS FUENTES', 41.65014000, -0.86333800, '0101000020E61000000B9C6C0377A0EBBF25E99AC937D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50372107406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50372107406.webp', 'https://www.flickr.com/photos/zaragozaantigua/50372107406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22327, 'Harinas Azâ”śâ”‚n c.1960', 'Imagen de la "Harinera de Francisco Azâ”śâ”‚n Aznar", establecida en la calle Yolanda de Bar nâ”¬â•‘ 11 a mediados de los aâ”śâ–’os 50 del pasado siglo. Por su capacidad molturadora (21 toneladas mâ”śÂ®tricas), era la 6â”¬Â¬ de las 13 harineras que operaban entonces en la ciudad. La reestructuraciâ”śâ”‚n del sector, a mediados de los aâ”śâ–’os 70, se llevâ”śâ”‚ por delante las grandes fâ”śĂ­bricas (Solans, La Imperial...) dejando apenas 5 instalaciones. Esta fâ”śĂ­brica, redenominada "Harinas Azâ”śâ”‚n, S.A.", fue una de ellas, hasta su cierre definitivo. En abril de 2005 las instalaciones fabriles fueron piqueteadas, y en su solar se levantaron los actuales bloques de los nâ”śâ•‘meros 5-7-9-11 de Yolanda de Bar, y el nâ”¬â•‘ 18 de Francisco de Quevedo, en un complejo de nombre "Edificio La Harinera". En la imagen, aspecto de la calle Yolanda de Bar con las edificaciones de la activa Harinera. Al otro lado de la calle, fuera de plano, el complejo de la fâ”śĂ­brica Schindler. Al fondo, a la derecha, el reformativo "El Buen Pastor". A la izquierda, los bloques de viviendas de Compromiso de Caspe, esquina con Doctor Iranzo nâ”¬â•‘ 52. Fuente visual: "Libro de Oro de Aragâ”śâ”‚n. Recuerdos grâ”śĂ­ficos de un siglo", Ediciones 94, 1997.', 1960, 1960, 1960, 'Anos 60', 'LAS FUENTES', 41.64041500, -0.86488300, '0101000020E610000049B9FB1C1FADEBBF156F641EF9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17197609351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17197609351.webp', 'https://www.flickr.com/photos/zaragozaantigua/17197609351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22461, 'Compromiso de Caspe 1962', 'En el Pleno municipal del emblemâ”śĂ­tico dâ”śÂˇa 8 de marzo de 1962, la Corporaciâ”śâ”‚n local acordâ”śâ”‚ redenominar el antiguo camino de las Fuentes con el mâ”śĂ­s moderno de avenida del Compromiso de Caspe, evento acontecido 550 aâ”śâ–’os antes. La imagen estâ”śĂ­ centrada en el tramo de los impares (desde el nâ”¬â•‘ 69) de la nueva avenida medieval, mâ”śĂ­s allâ”śĂ­ del Grupo Casta â”śĂĽlvarez (actual calle de Sancho Arroyo), hasta la calle del Doctor Iranzo. El lado de los pares, a la derecha, en construcciâ”śâ”‚n. Al fondo, la huerta de las Fuentes. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1962, 1962, 1962, 'Anos 60', 'LAS FUENTES', 41.64571600, -0.86592300, '0101000020E6100000AC55BB26A4B5EBBF814067D2A6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32070256013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32070256013.webp', 'https://www.flickr.com/photos/zaragozaantigua/32070256013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22501, 'Av. del Compromiso de Caspe c.1964', 'Imagen capturada desde cierta altura en el moderno inmueble del nâ”¬â•‘ 32 de la avenida del Compromiso de Caspe, esquinero con la calle del Prâ”śÂˇncipe Baltasar Carlos, y centrada en el tramo de esta avenida comprendido entre los recientes edificios de viviendas nâ”¬â•‘ 53-55-57 y el nâ”¬â•‘ 59, en primer tâ”śÂ®rmino, tan nuevo que en los pisos no vendidos conserva todavâ”śÂˇa las distintivas marcas de pintura sobre los cristales reciâ”śÂ®n instalados por Vidrios Ariâ”śâ–’o. Hasta 1962 este vial conservâ”śâ”‚ su denominaciâ”śâ”‚n de toda la vida: camino de Las Fuentes. A la izquierda, isleta en el despartidero entre la avenida y la calle de Nuestra Seâ”śâ–’ora del Pueyo.', 1964, 1964, 1964, 'Anos 60', 'LAS FUENTES', 41.64582700, -0.86713600, '0101000020E61000006DE525FF93BFEBBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49890765753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49890765753.webp', 'https://www.flickr.com/photos/zaragozaantigua/49890765753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22815, 'C.â”¬â•‘ de Fillas 1974', 'Inâ”śÂ®dita imagen capturada en el norteâ”śâ–’o tramo del camino de Fillas y centrada en la fachada sur de Fundiciones ATFHA, mâ”śĂ­s conocida como Fundiciones Tascâ”śâ”‚n por ser propiedad del ex-concejal Anselmo Tascâ”śâ”‚n Rodrâ”śÂˇguez, emplazada desde finales de los aâ”śâ–’os 50 en una zona rodeada de huerta, no muy lejos del râ”śÂˇo Huerva, del antiguo tâ”śÂ®rmino municipal del Jueves hoy absolutamente irreconocible, y que se encontrarâ”śÂˇa en la actual confluencia de las calles de Rusiâ”śâ–’ol, Santuario de Rodanas, Monasterio de Siresa y Monasterio de Guadalope. En el momento de realizar esta fotografâ”śÂˇa, esta fundiciâ”śâ”‚n comenzaba a estar rodeada de las modernas construcciones de esta zona en râ”śĂ­pido desarrollo urbanâ”śÂˇstico del barrio de las Fuentes, sobre todo de los bloques de viviendas mâ”śĂ­s occidentales de la calle del Monasterio de Siresa, y por el cercano Colegio Nacional (hoy Colegio Pâ”śâ•‘blico) Juliâ”śĂ­n Sanz Ibâ”śĂ­â”śâ–’ez. Esto motivâ”śâ”‚ las primeras denuncias vecinales por afecciones y peligrosidad, mâ”śĂ­s tarde canalizadas por la Asociaciâ”śâ”‚n de Cabezas de Familias del barrio cuando la distancia entre esta empresa y las viviendas era ya apenas una decena de metros. En 1977 una explosiâ”śâ”‚n en esta fundiciâ”śâ”‚n dio pie a una movilizaciâ”śâ”‚n popular y vecinal exigiendo su salida del barrio, sin que el entonces Ayuntamiento hiciera nada.', 1974, 1974, 1974, 'Anos 70', 'LAS FUENTES', 41.64787900, -0.86627800, '0101000020E610000035D1E7A38CB8EBBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51574903872.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51574903872.webp', 'https://www.flickr.com/photos/zaragozaantigua/51574903872/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22913, 'Nâ”¬Â¬ Sâ”¬Â¬ del Pueyo 1983', 'Imagen parcial de la antigua iglesia parroquial de "Cristo Rey" ("Rex Omnis Terrae Deus"), en la esquina entre la calle del Monasterio de Nâ”¬Â¬ Sâ”¬Â¬ del Pueyo (puerta de ingreso), y la de Sancho Arroyo, que conduce, al fondo, a la de Leopoldo Romeo. Esta iglesia habâ”śÂˇa sido inaugurada con notable boato a finales de 1939, con presencia del entonces Ministro de la Gobernaciâ”śâ”‚n, Ramâ”śâ”‚n Serrano Sâ”śâ•‘â”śâ–’er, ademâ”śĂ­s del arzobispo Domenech, el gobernador militar, el gobernador civil, el alcalde, el presidente de la Diputaciâ”śâ”‚n, el presidente de la Audiencia, el rector de la Universidad, y otras autoridades. Una centuria de las organizaciones juveniles de FET y de las JONS con banda de mâ”śâ•‘sica, ademâ”śĂ­s de las bandas Municipal, y Provincial, amenizaron el acto ante la nutrida parroquia asistente. A finales de los aâ”śâ–’os 80, toda esta zona fue objeto de una intensa transformaciâ”śâ”‚n: la parroquia fue derribada, y los esquineros y grandes terrenos anexos fueron intensamente urbanizados y edificados. Un nuevo y moderno conjunto parroquial de Cristo Rey fue edificado unas decenas de metros hacia la izquierda, en la misma calle. Fuente visual: Manuel Urbano, en zaragozaciudad.net/', 1983, 1983, 1983, 'Anos 80', 'LAS FUENTES', 41.64643000, -0.86650200, '0101000020E61000001B65FD6662BAEBBF9F93DE37BED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24086875223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24086875223.webp', 'https://www.flickr.com/photos/zaragozaantigua/24086875223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22997, 'Necrâ”śâ”‚polis romana 1991', 'Al este de la ciudad romana y al otro lado del râ”śÂˇo Huerva, se encontraba el cementerio mâ”śĂ­s extenso: la necrâ”śâ”‚polis oriental. Fue hallado en la actual calle del Monasterio de Nuestra Seâ”śâ–’ora del Pueyo, en el barrio de Las Fuentes. Fuente: Zaragoza. Prehistoria y arqueologâ”śÂˇa, Ayuntamiento de Zaragoza, 1991.', 1991, 1991, 1991, 'Anos 90', 'LAS FUENTES', 41.64620200, -0.86784500, '0101000020E610000068E89FE062C5EBBF0E4E44BFB6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24323799785.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24323799785.webp', 'https://www.flickr.com/photos/zaragozaantigua/24323799785/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24501, 'Yolanda de Bar 1978', 'Imagen capturada en una triangular replaceta que se formaba al final de la confluencia de las calles de Yolanda de Bar, y Francisco de Quevedo, y que antes de su urbanizaciâ”śâ”‚n era utilizada como aparcamiento de superficie, y tambiâ”śÂ®n como improvisado escenario, como la imagen ilustra, de una asamblea de trabajadores de GIESA- Schindler, afiliados al sindicato Comisiones Obreras, en las inmediaciones de esta importante empresa del sector del metal, que queda a las espaldas del fotâ”śâ”‚grafo. A la izquierda, fuera de plano, queda la calle Yolanda de Bar, que arranca en Miguel Servet, y tras cruzar la calle de San Joaquâ”śÂˇn (donde recae la fachada principal de GIESA, con su referencial puerta y esquinera torre), y enfrente, estaban las instalaciones de "Harinas Azâ”śâ”‚n, S.A." En la imagen, a la izquierda, el nâ”¬â•‘ 27 de la calle Francisco de Quevedo (ahora esquinero con la calle de Cubel, entonces inexistente), y a la derecha, las traseras del nâ”¬â•‘ 42 de la calle Tomâ”śĂ­s Higuera, en un entorno que luego ha conocido una profunda transformaciâ”śâ”‚n.', 1978, 1978, 1978, 'Anos 70', 'LAS FUENTES', 41.64089800, -0.86398100, '0101000020E610000029B16B7BBBA5EBBF310917F208D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31043857601.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31043857601.webp', 'https://www.flickr.com/photos/zaragozaantigua/31043857601/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24697, 'Compromiso de Caspe 1980', 'Fuente de las aguadoras, vulgo "Las alcahuetas", a la altura del nâ”śâ•‘mero 22 de la avenida Compromiso de Caspe (que sigue al fondo a la derecha) del barrio de Las Fuentes. Fuente: www.facebook.com/photo.php?fbid=370248613131974&set=o...', 1980, 1980, 1980, 'Anos 80', 'LAS FUENTES', 41.64595300, -0.86862500, '0101000020E6100000B29DEFA7C6CBEBBF65E08096AED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15693307291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15693307291.webp', 'https://www.flickr.com/photos/zaragozaantigua/15693307291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24705, 'Calle Juan Fabiani 1929', 'Imagen de la calle de Juan Fabiani, principal arteria del joven barrio de las Fuentes, trazado a comienzos de los aâ”śâ–’os 20 a unos 300 metros, en direcciâ”śâ”‚n noroeste, del despartidero entre la calle de Miguel Servet y el camino de San Josâ”śÂ®, con 87 parcelas ordenadas en torno a unos pocos viales, como este. La denominaciâ”śâ”‚n de esta calle rendâ”śÂˇa homenaje al que fue primer alcalde de la ciudad durante la dictadura de Primo de Rivera. Con la llegada de la democracia en 1931, esta calle fue redenominada de Santiago Rusiâ”śâ–’ol, y su paralela, hasta entonces de Martâ”śÂˇn Serrano, fue redenominada de Estanislao Figueras (el que fuera presidente de la Primera Repâ”śâ•‘blica). Tras el 18 de julio de 1936, la calle del pintor Santiago Rusiâ”śâ–’ol conservâ”śâ”‚ su nombre, pero la de Figueras perdiâ”śâ”‚ su nombre, y se quedâ”śâ”‚ como homenaje al bonito municipio gerundâ”śÂ®s del Ampurdâ”śĂ­n de ese nombre. La captura fotogrâ”śĂ­fica se ha realizado, posiblemente, desde la misma calle de Juan Fabiani, casi al final, donde comienza, a la derecha (fuera de plano), la calle de Rosales. Por las traseras de las parcelas de la izquierda fluâ”śÂˇa al aire la acequia de Las Fuentes, y algo mâ”śĂ­s a la izquierda pasaba el antiguo camino de Las Fuentes, origen de la posterior avenida del Compromiso de Caspe.', 1929, 1929, 1929, 'Anos 20', 'LAS FUENTES', 41.64747200, -0.86678100, '0101000020E6100000E469F981ABBCEBBFB189CC5CE0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32522371835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32522371835.webp', 'https://www.flickr.com/photos/zaragozaantigua/32522371835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24710, 'C.â”¬â•‘ de las Torres 1991', 'Imagen capturada desde la altura de los bloques de la calle del Doctor Joaquâ”śÂˇn Aznar Molina inmediatos al râ”śÂˇo Huerva, y centrada en el tramo de la prolongaciâ”śâ”‚n del camino de las Torres comprendido entre la calle del Santuario de Rodanas, a la izquierda, y la de Jorge Cocci, a la derecha y fuera de plano. Tras el muro perimetral de primer tâ”śÂ®rmino, solares y traseras de las parcelas vertebradas por la calle de Figueras, seguidas de las calles de Santiago Rusiâ”śâ–’ol y Pintor Zuloaga, pionero entorno del actual barrio de Las Fuentes. A mediados de la dâ”śÂ®cada, los solares de primer tâ”śÂ®rmino serâ”śÂˇan transformados en zona verde que, delimitada por el camino de las Torres y la nueva calle de la Villa de Chiprana, serâ”śÂˇa denominada parque de Las Glorietas de Goya.', 1991, 1991, 1991, 'Anos 90', 'LAS FUENTES', 41.64799100, -0.86861700, '0101000020E6100000FCFCF7E0B5CBEBBF198D7C5EF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450082171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450082171.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450082171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24984, 'Proyecto parque Bruil 1956', 'Proyecto de parque pâ”śâ•‘blico en los terrenos de la Torre de Bruil, sitos en la calle del Asalto. Zaragoza, 1956. Este parque serâ”śĂ­ inaugurado en 1965. Fuente: AMZ, Sign. 0410.', 1956, 1956, 1956, 'Anos 50', 'LAS FUENTES', 41.64987300, -0.86839300, '0101000020E61000001669E21DE0C9EBBFD6C6D8092FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27933470564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27933470564.webp', 'https://www.flickr.com/photos/zaragozaantigua/27933470564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
